import { useMemo, useState } from "react";
import "./styles.css";
import { sampleNotice, actionCards, sourceSnippets, uncertaintyItems } from "./data";

export default function Page() {
  const [noticeText, setNoticeText] = useState(sampleNotice.text);
  const [grade, setGrade] = useState(sampleNotice.grade);
  const [familyContext, setFamilyContext] = useState(sampleNotice.familyContext);
  const [selectedSnippetId, setSelectedSnippetId] = useState(actionCards[0].sourceSnippetId);
  const grouped = useMemo(() => ({
    today: actionCards.filter((card) => card.status === "today"),
    thisWeek: actionCards.filter((card) => card.status === "this_week"),
    ask: actionCards.filter((card) => card.status === "ask")
  }), []);

  return (
    <main className="otayori-shell">
      <header className="hero">
        <div>
          <p className="eyebrow">Prodia Concept Artifact</p>
          <h1>おたよりルート</h1>
          <p>学校や自治体のお知らせを、家庭ごとの行動ルート、確認質問、原文根拠に分けます。</p>
        </div>
        <aside className="safety-note">公式文書の代替ではありません。原文にない内容は判断せず、確認待ちとして残します。</aside>
      </header>
      <section className="workspace" aria-label="おたよりルート ワークスペース">
        <section className="input-panel" aria-label="入力">
          <div className="panel-head"><span>Input</span><button type="button" onClick={() => { setNoticeText(sampleNotice.text); setGrade(sampleNotice.grade); setFamilyContext(sampleNotice.familyContext); }}>サンプル読み込み</button></div>
          <label>お知らせ本文<textarea value={noticeText} onChange={(event) => setNoticeText(event.target.value)} /></label>
          <div className="field-row"><label>学年<input value={grade} onChange={(event) => setGrade(event.target.value)} /></label><label>家庭メモ<input value={familyContext} onChange={(event) => setFamilyContext(event.target.value)} /></label></div>
          <div className="source-box">
            <h2>原文根拠</h2>
            {sourceSnippets.map((snippet) => <button key={snippet.id} type="button" className={snippet.id === selectedSnippetId ? "snippet active" : "snippet"} onClick={() => setSelectedSnippetId(snippet.id)}><strong>{snippet.label}</strong><span>{snippet.text}</span><small>{snippet.whyUsed}</small></button>)}
          </div>
        </section>
        <section className="route-panel" aria-label="行動ルート">
          <div className="panel-title"><span>Route</span><h2>家庭の次アクション</h2></div>
          <div className="route-columns">
            <RouteColumn title="今日やる" cards={grouped.today} onPick={setSelectedSnippetId} />
            <RouteColumn title="今週やる" cards={grouped.thisWeek} onPick={setSelectedSnippetId} />
            <RouteColumn title="確認待ち" cards={grouped.ask} onPick={setSelectedSnippetId} />
          </div>
        </section>
        <aside className="uncertainty-panel" aria-label="不明点">
          <div className="panel-title"><span>Unknown</span><h2>まだ判断しないこと</h2></div>
          {uncertaintyItems.map((item) => <article key={item.id} className="uncertainty-card"><strong>{item.question}</strong><p>{item.whyUnknown}</p><small>確認先: {item.suggestedAskTarget}</small></article>)}
        </aside>
      </section>
    </main>
  );
}

function RouteColumn({ title, cards, onPick }: { title: string; cards: typeof actionCards; onPick: (id: string) => void }) {
  return <div className="route-column"><h3>{title}</h3>{cards.map((card) => <button key={card.id} type="button" className="action-card" onClick={() => onPick(card.sourceSnippetId)}><span>{card.ownerLabel}</span><strong>{card.title}</strong><small>{card.dueLabel}</small><p>{card.reason}</p><em>根拠を見る</em></button>)}</div>;
}

export const sampleNotice = {
  grade: "小学3年",
  familyContext: "平日は保護者Aが夕方に確認。アレルギー確認が必要。",
  text: `校外学習のお知らせ\n6月30日(火)に中央公園へ校外学習へ行きます。参加同意書は6月27日(金)までに担任へ提出してください。\n持ち物は水筒、帽子、筆記用具、雨具です。昼食の有無は後日連絡します。\n食物アレルギーや体調面で配慮が必要な場合は、連絡帳でお知らせください。`
};

export const sourceSnippets = [
  { id: "src_deadline", label: "提出期限", text: "参加同意書は6月27日(金)までに担任へ提出してください。", whyUsed: "期限と提出先が明記されているため、今日の行動カードに変換。" },
  { id: "src_items", label: "持ち物", text: "持ち物は水筒、帽子、筆記用具、雨具です。", whyUsed: "準備物が列挙されているため、今週の準備カードに変換。" },
  { id: "src_lunch", label: "未確定情報", text: "昼食の有無は後日連絡します。", whyUsed: "原文で未確定とされているため、確認待ちに分離。" },
  { id: "src_allergy", label: "家庭条件", text: "食物アレルギーや体調面で配慮が必要な場合は、連絡帳でお知らせください。", whyUsed: "家庭メモと関連するため、確認質問に変換。" }
];

export const actionCards = [
  { id: "act_consent", status: "today", title: "参加同意書を確認して提出準備", ownerLabel: "保護者", dueLabel: "6月27日(金)まで", reason: "提出期限と提出先が原文にあるため、最優先の行動。", sourceSnippetId: "src_deadline", confidence: "high" },
  { id: "act_items", status: "this_week", title: "水筒・帽子・筆記用具・雨具をそろえる", ownerLabel: "家庭", dueLabel: "前日まで", reason: "持ち物が明記されており、購入や準備が必要な可能性がある。", sourceSnippetId: "src_items", confidence: "high" },
  { id: "act_lunch", status: "ask", title: "昼食の有無は後続連絡を待つ", ownerLabel: "確認待ち", dueLabel: "後日", reason: "原文が未確定としているため、AIが断定しない。", sourceSnippetId: "src_lunch", confidence: "medium" },
  { id: "act_allergy", status: "ask", title: "アレルギー配慮を連絡帳で相談", ownerLabel: "保護者", dueLabel: "早めに確認", reason: "家庭メモと原文の配慮連絡が一致している。", sourceSnippetId: "src_allergy", confidence: "medium" }
] as const;

export const uncertaintyItems = [
  { id: "unk_lunch", question: "昼食は必要か", whyUnknown: "原文が後日連絡としており、現時点では判断できない。", suggestedAskTarget: "学校からの続報" },
  { id: "unk_weather", question: "雨天時の実施判断", whyUnknown: "雨具は指定されているが、中止・延期条件は書かれていない。", suggestedAskTarget: "担任または学校のお知らせ" }
];

.otayori-shell { min-height: 100vh; padding: 24px; background: #f4f7f4; color: #17201a; font-family: system-ui, sans-serif; }
.hero { display: grid; grid-template-columns: minmax(0, 1fr) 320px; gap: 20px; align-items: end; margin-bottom: 18px; }
.eyebrow { margin: 0 0 8px; color: #5b6f3a; font-size: 12px; font-weight: 800; text-transform: uppercase; }
h1 { margin: 0; font-size: 42px; line-height: 1.08; letter-spacing: 0; }
.hero p { max-width: 760px; margin: 10px 0 0; line-height: 1.8; }
.safety-note { padding: 14px; border: 1px solid #c8d4b8; border-radius: 8px; background: #fffef7; line-height: 1.6; font-weight: 700; }
.workspace { display: grid; grid-template-columns: minmax(260px, 360px) minmax(0, 1fr) minmax(240px, 320px); gap: 16px; align-items: start; }
.input-panel, .route-panel, .uncertainty-panel { border: 1px solid #d5dfd1; border-radius: 8px; background: #ffffff; padding: 16px; }
.panel-head { display: flex; align-items: center; justify-content: space-between; gap: 10px; margin-bottom: 12px; }
.panel-head span, .panel-title span { color: #5b6f3a; font-size: 12px; font-weight: 900; text-transform: uppercase; }
button { font: inherit; }
.panel-head button { min-height: 36px; border: 1px solid #8fa56c; border-radius: 6px; background: #eef6df; color: #26331f; font-weight: 800; cursor: pointer; }
label { display: grid; gap: 7px; font-size: 13px; font-weight: 800; }
textarea, input { width: 100%; border: 1px solid #cad6c5; border-radius: 6px; padding: 10px; color: #17201a; background: #fbfcfa; font: inherit; }
textarea { min-height: 220px; resize: vertical; line-height: 1.65; }
.field-row { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin: 12px 0; }
.source-box { display: grid; gap: 8px; margin-top: 14px; }
.source-box h2, .panel-title h2 { margin: 0; font-size: 18px; letter-spacing: 0; }
.snippet, .action-card { width: 100%; border: 1px solid #d5dfd1; border-radius: 8px; background: #fbfcfa; color: inherit; text-align: left; cursor: pointer; }
.snippet { display: grid; gap: 6px; padding: 10px; }
.snippet.active { border-color: #5b6f3a; background: #f0f6e8; box-shadow: inset 4px 0 0 #5b6f3a; }
.snippet span, .snippet small, .action-card p, .action-card small, .uncertainty-card p, .uncertainty-card small { line-height: 1.55; color: #4d5b4d; }
.route-panel { min-width: 0; }
.route-columns { display: grid; grid-template-columns: repeat(3, minmax(0, 1fr)); gap: 12px; margin-top: 14px; }
.route-column { display: grid; align-content: start; gap: 10px; min-width: 0; }
.route-column h3 { margin: 0; font-size: 14px; }
.action-card { display: grid; gap: 7px; min-height: 168px; padding: 12px; }
.action-card span { color: #6b4f1d; font-size: 12px; font-weight: 900; }
.action-card strong { font-size: 15px; line-height: 1.35; }
.action-card em { color: #2d5f54; font-size: 12px; font-style: normal; font-weight: 900; }
.uncertainty-panel { display: grid; gap: 12px; }
.uncertainty-card { border: 1px solid #e0d4c1; border-radius: 8px; background: #fffaf0; padding: 12px; }
.uncertainty-card strong { display: block; line-height: 1.4; }
@media (max-width: 980px) { .hero, .workspace { grid-template-columns: 1fr; } .route-columns { grid-template-columns: 1fr; } h1 { font-size: 34px; } .field-row { grid-template-columns: 1fr; } }
